	<script>
document.addEventListener('DOMContentLoaded', () => {
	const valuationWrap = document.querySelector('.valuation-btn-wrap');
	const footer = document.querySelector('footer');

	//if (!valuationWrap || !footer) return;

	// const TOP_HIDE_OFFSET = 120;

	const updateValuationButton = () => {
		// const isNearTop = window.scrollY <= TOP_HIDE_OFFSET;

		const footerRect = footer.getBoundingClientRect();
		const viewportHeight = window.innerHeight || document.documentElement.clientHeight;

		// hide once footer starts entering viewport
		const isOverFooter = footerRect.top <= viewportHeight;

		const shouldHide = isOverFooter;

		//valuationWrap.classList.toggle('is-hidden', shouldHide);
		//valuationWrap.classList.toggle('is-visible', !shouldHide);
	};

	let ticking = false;

	const onScrollOrResize = () => {
		if (ticking) return;

		window.requestAnimationFrame(() => {
			//updateValuationButton();
			ticking = false;
		});

		ticking = true;
	};

	window.addEventListener('scroll', onScrollOrResize, {
		passive: true
	});
	window.addEventListener('resize', onScrollOrResize);

	updateValuationButton();


	// Modal - Functionality
	const modal = document.getElementById("valuation-modal");

	function openModal() {
		modal.style.display = "flex";
	}

	function closeModal() {
		modal.style.display = "none";
	}

	// 👇 IMPORTANT: make them global so inline onclick can access them
	window.openModal = openModal;
	window.closeModal = closeModal;

	const footerLink = document.querySelector('#menu-footer-sell .valuation');


	if (footerLink) {
		footerLink.addEventListener('click', () => {
			openModal();
		});
	}

	// click outside to close
	modal.addEventListener("click", function(e) {
		if (e.target === modal) {
			closeModal();
		}
	});

	// ESC key close
	document.addEventListener("keydown", function(e) {
		if (e.key === "Escape") {
			closeModal();
		}
	});
});
	</script>